class Solution:
    def maximumEnergy(self, energy: List[int], k: int) -> int:
        n = len(energy)
        max_energy = float('-inf')
        for i in range(n):
            current = 0
            j = i
            while j < n:
                current += energy[j]
                j += k
            max_energy = max(max_energy, current)
        return max_energy
